const trapFocusHandlers = {};

function getFocusableElements(container) {
  return Array.from(
    container.querySelectorAll(
      "summary, a[href], button:enabled, [tabindex]:not([tabindex^='-']), [draggable], area, input:not([type=hidden]):enabled, select:enabled, textarea:enabled, object, iframe"
    )
  );
}

function removeTrapFocus(elementToFocus = null) {
  document.removeEventListener('focusin', trapFocusHandlers.focusin);
  document.removeEventListener('focusout', trapFocusHandlers.focusout);
  document.removeEventListener('keydown', trapFocusHandlers.keydown);

  if (elementToFocus) elementToFocus.focus();
}

function trapFocus(container, elementToFocus = container) {
  var elements = getFocusableElements(container);
  var first = elements[0];
  var last = elements[elements.length - 1];

  removeTrapFocus();

  trapFocusHandlers.focusin = (event) => {
    if (
      event.target !== container &&
      event.target !== last &&
      event.target !== first
    )
      return;

    document.addEventListener('keydown', trapFocusHandlers.keydown);
  };

  trapFocusHandlers.focusout = function () {
    document.removeEventListener('keydown', trapFocusHandlers.keydown);
  };

  trapFocusHandlers.keydown = function (event) {
    if (event.code.toUpperCase() !== 'TAB') return; // If not TAB key
    // On the last focusable element and tab forward, focus the first element.
    if (event.target === last && !event.shiftKey) {
      event.preventDefault();
      first.focus();
    }

    //  On the first focusable element and tab backward, focus the last element.
    if (
      (event.target === container || event.target === first) &&
      event.shiftKey
    ) {
      event.preventDefault();
      last.focus();
    }
  };

  document.addEventListener('focusout', trapFocusHandlers.focusout);
  document.addEventListener('focusin', trapFocusHandlers.focusin);

  elementToFocus.focus();

  if (
    elementToFocus.tagName === 'INPUT' &&
    ['search', 'text', 'email', 'url'].includes(elementToFocus.type) &&
    elementToFocus.value
  ) {
    elementToFocus.setSelectionRange(0, elementToFocus.value.length);
  }
}



class ModalDialog extends HTMLElement {
  constructor() {
    super();
    this.querySelector('[id^="ModalClose-"]').addEventListener(
      'click',
      this.hide.bind(this, false)
    );
    this.addEventListener('keyup', (event) => {
      if (event.code.toUpperCase() === 'ESCAPE') this.hide();
    });

    this.addEventListener('click', (event) => {
      if (event.target === this) this.hide();
    });
  }

  show(opener) {
    this.openedBy = opener;
    
    this.setAttribute('open', '');
    
    trapFocus(this, this.querySelector('[role="dialog"]'));
  }

  hide() {
    this.removeAttribute('open');
    document.body.dispatchEvent(new CustomEvent('modalClosed'));
    
    removeTrapFocus(this.openedBy);
  }
}

customElements.define('modal-dialog', ModalDialog);



class QuickbuyTrigger extends HTMLElement {
  constructor() {
    super();

    this.productUrl = this.dataset.productUrl.split("?")[0];

    this.button = this.querySelector('button');

    this.button.addEventListener('click', this.onButtonClick.bind(this));
  }

  onButtonClick(e) {
    e.preventDefault();
    
    fetch(`${this.productUrl}?section_id=product_quickview`)
      .then((response) => response.text())
      .then((responseText) => {
        const responseHTML = new DOMParser().parseFromString(responseText, 'text/html');

        const oldModal = document.querySelector('#QuickviewModal');
        if (oldModal) {
          oldModal.remove();
        }

        const modal = responseHTML.querySelector('#QuickviewModal');
        document.body.appendChild(modal);

        modal.show(this.button);
      });
  }
}

if (!customElements.get('quickbuy-trigger')) {
  customElements.define('quickbuy-trigger', QuickbuyTrigger);
}




class QuickbuyContainer extends HTMLElement {
  constructor() {
    super();

    this.productUrl = this.dataset.productUrl;
    this.form = this.querySelector('#QuickbuyForm');

    this.addEventListener('change', this.handleOnChange.bind(this));

    this.form.addEventListener('submit', this.handleSubmit.bind(this));
  }

  handleOnChange(event) {
    const optionValueSelectors = event.target.closest('.product__variant-picker');

    const selectedOptionValues = Array.from(
        optionValueSelectors.querySelectorAll('input[type="radio"]:checked')
      ).map(({value}) => value);

    const params = selectedOptionValues.length > 0
      ? `&option_values=${selectedOptionValues.join(',')}`
      : '';

    console.log(`${this.productUrl}?section_id=product_quickview${params}`);

    fetch(`${this.productUrl}?section_id=product_quickview${params}`)
      .then((response) => response.text())
      .then((responseText) => {
        const responseHTML = new DOMParser().parseFromString(responseText, 'text/html');

        const imageContainer = responseHTML.querySelector('#QuickbuyImage');
        const priceContainer = responseHTML.querySelector('#QuickbuyPrice');
        const formContainer = responseHTML.querySelector('#QuickbuyForm');

        const optionLabels = responseHTML.querySelectorAll('.product__variant-option-label');

        this.querySelector('#QuickbuyImage').innerHTML = imageContainer.innerHTML;
        this.querySelector('#QuickbuyPrice').innerHTML = priceContainer.innerHTML;
        this.querySelector('#QuickbuyForm').innerHTML = formContainer.innerHTML;

        this.querySelectorAll('.product__variant-option-label').forEach((label, index) => {
          label.innerHTML = optionLabels[index].innerText;
        });
      });
  }

  handleSubmit(event) {
    event.preventDefault();

      var formData = new FormData(this.form);
      var formObject = {
        id: formData.get('id'),
        quantity: 1
      };

      const items = [formObject];
      window.addToCart(items).then((response) => {
        this.remove();
      }).catch((error) => {
        console.error(error);
      });
  }
}

if (!customElements.get('quickbuy-container')) {
  customElements.define('quickbuy-container', QuickbuyContainer);
}